class resident:    def __init__(self, name):        self.name = name        self.hunger = 60        self.energy = 80        self.is_alive = True    def status(self):        return f'{self.name} | Голод: {self.hunger} | Энергия: {self.energy}'    def live_day(self):        'Пассивное старение/усталось'        self.hunger -= 15        self.energy -= 15        if self.hunger <= 0 or self.energy <= 0:            self.is_alive = False    def react_to_mess(self):        'Пример полиморфизма: каждый житель по-разнаму реагирует на хлам'        passclass workersim(resident):    def __init__(self, name, money):        super().__init__(name)        self.money = money    def work(self):        print(f'{self.name} пашет на двух работах! +150$')        self.money += 150        self.energy -= 40        self.hunger -= 20    def react_to_mess(self):        print(f"{self.name}: 'Опять этот мусор! Cил моих нет!' (Минус 20 настроения)")        self.energy -= 10class lazysim(resident):    def __init__(self, name):        super().__init__(name)        self.laziness = 100    def live_day(self):        self.hunger -= 5        self.energy -= 5        if self.hunger <= 0 or self.energy <= 0:            self.is_alive = False    def sleep_on_trath(self):        print(f'{self.name} прилёг на гору грязного бельяю Удобно!')        self.energy += 40        self.hunger -= 5    def react_to_mess(self):        print(f"{self.name}: 'Какой мусор? Это элементы инитерьера...'")class robotsim(resident):    def __init__(self, name):        super().__init__(name)    def react_to_mess(self):        if is_messy == True and self.hunger >= 30:            print(f'{self.name}: Обнаружен мусор: начинаю уборку')            is_messy = False            self.hunger -= 30worker = workersim('Артур', 100)lazy_gay = lazysim('Ларри')roommates = [worker, lazy_gay]robot = robotsim('Робопылесос')day = 1is_messy = Trueprint('Симулятор камуналки запущен')while True:    print(f'\n=== ДЕНЬ {day} ===')    if not all(r.is_alive for r in roommates):        dead = next(r for r in roommates if not r.is_alive)        print(f'Конец игры: {dead.name} покинул этот мир.')        break    print(f"Общак Артура: {worker.money} | Состояние {'ХЛАМ' if is_messy else 'ЧИСТО'}")    for r in roommates:        print(r.status())    print('\nВаш выбор:')    print('1. Артур: Пойти на работу (+150$)')    print('2. Артур: Купить пиццу на всех (-50$)')    print('3. Ларри: Поспать в куче хлама (+энергия)')    print('4. Ларри: Попросить у Артура денег на еду')    print('5. Артур: Убраться в комнате (Артур запускает робота)')    print('0. Выход')    choice = input('Действие: ')    if choice == '1':        worker.work()    elif choice == '2':        if worker.money >= 50:            worker.money -= 50            for r in roommates:                r.hunger = min(100, r.hunger + 40)            print('Пицца заказана! Все поели.')        else:            print('Нет денег на пиццу!')    elif choice == '3':        if is_messy:            lazy_gay.sleep_on_trath()        else:            print('Хлама нет пришлось спать на голом полу. Спина болит.')            lazy_gay.energy += 10    elif choice == '4':        print(f'Ларри клянчит деньги. Артур в ярости!')        worker.energy -= 5    elif choice == '5':        robotsim.react_to_mess()        print(f'Робот убирался пол дня')    elif choise == '0':        break    print('\n Ночь в коммуналке...')    for r in roommates:        r.live_day()        if is_messy:            r.react_to_mess()    day += 1print('Игра завершена.')